// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





function getWeatherIcon(condition?: string) {
  const c = (condition || '').toLowerCase();
  if (c.includes('sun') || c.includes('clear')) return 'sun';
  if (c.includes('rain') || c.includes('drizzle') || c.includes('shower')) return 'cloud-rain';
  if (c.includes('storm') || c.includes('lightning') || c.includes('thunder')) return 'cloud-lightning';
  if (c.includes('snow') || c.includes('ice') || c.includes('hail')) return 'snowflake';
  if (c.includes('cloud') || c.includes('overcast') || c.includes('mist') || c.includes('fog')) return 'cloud';
  if (c.includes('wind') || c.includes('breeze')) return 'wind';
  return 'sun';
}
export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract


  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8)">
      <Card padding="var(--ggui-spacing-8)" shadow="lg" radius="xl" as={Pressable} pressStyle={{ transform: 'scale(0.99)' }}>
        <Stack gap="var(--ggui-spacing-8)">
          {/* Header section with City and Icon */}
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Today's Forecast</Text>
            </Stack>
            <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-lg)">
              <Icon name={getWeatherIcon(props.condition)} size={48} color="var(--ggui-color-primary-600)" />
            </Box>
          </Row>

          {/* Main Temperature Display */}
          <Stack align="center" gap="var(--ggui-spacing-2)">
            <Row align="start" gap="var(--ggui-spacing-1)">
              <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface)">{props.temperature}</Text>
              <Text size="xl" weight="semibold" color="var(--ggui-color-primary-600)" style={{ marginTop: 'var(--ggui-spacing-2)' }}>°{props.unit}</Text>
            </Row>
            <Badge variant="primary" size="lg">{props.condition}</Badge>
          </Stack>

          {/* Environmental Stats */}
          <Box background="var(--ggui-color-surfaceVariant)" padding="var(--ggui-spacing-4)" borderRadius="var(--ggui-shape-radius-lg)">
            <Row justify="around" align="center">
              <Stack align="center" gap="var(--ggui-spacing-1)">
                <Icon name="droplets" size={20} color="var(--ggui-color-primary-500)" />
                <Text variant="label" weight="bold">{props.humidity}%</Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
              </Stack>
              <Divider orientation="vertical" margin="var(--ggui-spacing-2)" />
              <Stack align="center" gap="var(--ggui-spacing-1)">
                <Icon name="wind" size={20} color="var(--ggui-color-primary-500)" />
                <Text variant="label" weight="bold">{props.windSpeed} km/h</Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
              </Stack>
            </Row>
          </Box>

          <Divider />

          {/* 5-Day Forecast Strip */}
          <Stack gap="var(--ggui-spacing-4)">
            <Text variant="label" weight="semibold" color="var(--ggui-color-onSurfaceVariant)">5-DAY FORECAST</Text>
            <Row justify="between" align="center" wrap>
              {props.forecast?.map((day, idx) => (
                <Box key={idx} padding="var(--ggui-spacing-2)" as={Hoverable} hoverStyle={{ background: 'var(--ggui-color-surfaceVariant)', borderRadius: 'var(--ggui-shape-radius-md)' }}>
                  <Stack align="center" gap="var(--ggui-spacing-2)">
                    <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant)">{day.day}</Text>
                    <Icon name={getWeatherIcon(day.icon)} size={24} color="var(--ggui-color-primary-600)" />
                    <Stack gap={0} align="center">
                      <Text variant="bodySmall" weight="bold">{day.high}°</Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" size="xs">{day.low}°</Text>
                    </Stack>
                  </Stack>
                </Box>
              ))}
            </Row>
          </Stack>
        </Stack>
      </Card>
    </Container>

  );
}
